const input = $input.first().json;

function collectText(value) {
  if (value === null || value === undefined) return '';

  if (typeof value === 'string') return value;

  if (Array.isArray(value)) {
    return value.map(collectText).filter(Boolean).join('\n');
  }

  if (typeof value === 'object') {
    const candidates = [
      value.content,
      value.text,
      value.output,
      value.response,
      value.message,
      value.data
    ];

    return candidates.map(collectText).filter(Boolean).join('\n');
  }

  return String(value);
}

function normalizeDate(value) {
  if (!value) return null;

  const s = String(value).trim();

  // already ISO: 2026-05-26
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) {
    return s;
  }

  // DD/MM/YYYY or DD.MM.YYYY or DD-MM-YYYY
  const dmy = s.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{4})$/);
  if (dmy) {
    const dd = dmy[1].padStart(2, '0');
    const mm = dmy[2].padStart(2, '0');
    const yyyy = dmy[3];

    return `${yyyy}-${mm}-${dd}`;
  }

  // YYYY/MM/DD or YYYY.MM.DD
  const ymd = s.match(/^(\d{4})[./](\d{1,2})[./](\d{1,2})$/);
  if (ymd) {
    const yyyy = ymd[1];
    const mm = ymd[2].padStart(2, '0');
    const dd = ymd[3].padStart(2, '0');

    return `${yyyy}-${mm}-${dd}`;
  }

  return s;
}

let content = collectText(input).trim();

content = content
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

const firstBrace = content.indexOf('{');
const lastBrace = content.lastIndexOf('}');

if (firstBrace >= 0 && lastBrace > firstBrace) {
  content = content.slice(firstBrace, lastBrace + 1);
}

let parsed;

try {
  parsed = JSON.parse(content);
} catch (e) {
  return [{
    json: {
      parse_error: true,
      error_message: e.message,
      raw_content: content
    }
  }];
}

const normalizedDate = normalizeDate(
  parsed.receipt_date ||
  parsed.transaction_date ||
  parsed.date
);

return [{
  json: {
    ...parsed,
    receipt_date: normalizedDate,
    transaction_date: normalizedDate,
    parse_error: false
  }
}];

const receiptId = $('Insert receipt').first().json.id;
const receipt = $('Parse receipt JSON').first().json;

const items = Array.isArray(receipt.items) ? receipt.items : [];

function normalizeLanguage(value) {
  const v = String(value || '').trim().toLowerCase();

  const map = {
    spanish: 'es',
    español: 'es',
    espanol: 'es',
    es: 'es',

    russian: 'ru',
    русский: 'ru',
    ru: 'ru',

    english: 'en',
    inglés: 'en',
    ingles: 'en',
    en: 'en'
  };

  return map[v] || 'es';
}

return items.map(item => {
  const quantity = Number(item.quantity || 1);
  const unitPrice = Number(item.unit_price || item.price || item.amount || 0);
  const amount = Number(item.amount || quantity * unitPrice || 0);

  return {
    json: {
      receipt_id: receiptId,
      item_name_original: item.item_name_original || item.name || '',
      item_language: normalizeLanguage(item.item_language || receipt.language),
      quantity,
      unit_price: unitPrice,
      amount,
      category_id: item.category_id || null,
      product_id: item.product_id || null
    }
  };
});

const products = $('Get uncategorized products').first().json.products || [];
const categories = $('Get user categories').all().map(i => i.json);

const prompt = `
Categorize receipt products.

Return only valid JSON.
No markdown.

JSON format:
{
  "assignments": [
    {
      "product_id": 123,
      "category_id": 456
    }
  ]
}

Products:
${JSON.stringify(products, null, 2)}

Categories:
${JSON.stringify(categories, null, 2)}

Rules:
- Use only category_id from Categories.
- Use only product_id from Products.
- If unsure, skip product.
`;

return [{
  json: {
    prompt
  }
}];

