from moneytrack.receipts
where telegram_file_id='{{ $('Get user context').first().json.telegram_file_id }}'
) as duplicate_found;

select exists(
select 1
from moneytrack.receipts r
join moneytrack.app_users u on u.id=r.user_id
where u.telegram_user_id={{ $('Get user context').first().json.telegram_user_id }}
and r.receipt_fingerprint='{{ $json.receipt_fingerprint }}'
) as semantic_duplicate_found;

