function normText(value) {
  return String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9а-яё]+/gi, '');
}
const receipt = { ...$json };
const settings = $('Get user context').first().json;
const baseCurrency = settings.base_currency || settings.report_currency;
if (!baseCurrency) {
  throw new Error('Missing base/report currency in user context');
}
const shop = normText(receipt.shop_name);
const date = String(receipt.receipt_date || '').substring(0, 10);
const amount = Number(receipt.total_amount || 0).toFixed(2);
const currency = String(receipt.currency || baseCurrency).toUpperCase();
const itemsCount = Array.isArray(receipt.items) ? receipt.items.length : 0;
const base = `${shop}|${date}|${amount}|${currency}|${itemsCount}`;
return [{
  json: {
    ...receipt,
    currency,
    receipt_fingerprint: base
  }
}];

const data = $input.first().json;

let raw =
  data.output?.[0]?.content?.[0]?.text ??
  data.message?.content ??
  data.text ??
  data.output_text ??
  data.output;

if (!raw) {
  throw new Error('No model text found: ' + JSON.stringify(data));
}

raw = String(raw)
  .trim()
  .replace(/^```json/i, '')
  .replace(/^```/i, '')
  .replace(/```$/i, '')
  .trim();

const parsed = JSON.parse(raw);

return [{
  json: {
    operation_type: parsed.operation_type || 'unknown',

    amount: parsed.amount == null ? null : Number(parsed.amount),
    currency: parsed.currency || $('Get user context').item.json.base_currency,

    description: parsed.description || '',

    from_account_hint: parsed.from_account_hint || null,
    to_account_hint: parsed.to_account_hint || null,

    amount_from: parsed.amount_from == null ? null : Number(parsed.amount_from),
    currency_from: parsed.currency_from || null,
    amount_to: parsed.amount_to == null ? null : Number(parsed.amount_to),
    currency_to: parsed.currency_to || null,

    transaction_date: parsed.transaction_date || null,

    raw_text: $('Get user context').first().json.message_text
  }
}];

const text = $('Get user context').first().json.message_text || '';
const parts = text.trim().toLowerCase().replace(/\s+/g, ' ').split(' ');

const allowedTypes = [
  'all',
  'income',
  'expense',
  'adjustment',
  'transfer',
  'exchange',
  'transferexchange',
  'openingbalance'
];

let operation_type = 'all';
let limit = 10;

for (const part of parts.slice(1)) {
  if (allowedTypes.includes(part)) {
    operation_type = part;
  } else if (/^\d+$/.test(part)) {
    limit = Math.min(Number(part), 100);
  }
}

return [{
  json: {
    operation_type,
    limit
  }
}];

const text = $('Get user context').first().json.message_text || '';
const parts = text.trim().split(/\s+/);

const txId = parts[1] ? Number(parts[1]) : null;

return [{
  json: {
    transaction_id: Number.isInteger(txId) ? txId : null,
    mode: Number.isInteger(txId) ? 'delete' : 'preview'
  }
}];

const text = $('Get user context').first().json.message_text || '';
const parts = text.trim().split(/\s+/);

const transactionId = Number(parts[1]);
const accountHint = parts.slice(2).join(' ').trim();

return [{
  json: {
    transaction_id: Number.isInteger(transactionId) && transactionId > 0
      ? transactionId
      : null,
    account_hint: accountHint
  }
}];

const rows = $input.all().map(i => i.json);
const translations = $('Get Translations for accounts').all().map(i => i.json);
const messages = {};
for (const row of translations) {
  messages[`${row.module}.${row.message_key}`] = row.message_text;
}
const requiredKeys = [
  'accounts.title',
  'accounts.base_currency',
  'accounts.total',
  'common.miniapp'
];
const missing = requiredKeys.filter(key => !messages[key]);
if (missing.length > 0) {
  throw new Error(`Missing accounts translations: ${missing.join(', ')}`);
}
const t = {
  title: messages['accounts.title'],
  baseCurrency: messages['accounts.base_currency'],
  total: messages['accounts.total'],
  miniapp: messages['common.miniapp']
};
const ctx = $('Get user context').first().json;
const localeMap = { ru: 'ru-RU', en: 'en-US', es: 'es-ES' };
const locale = localeMap[ctx.language_code] || 'en-US';
const baseCurrency = rows[0]?.base_currency || ctx.base_currency;
if (!baseCurrency) {
  throw new Error('Missing base currency in user context');
}
const byId = {};
const roots = [];
const rates = {};
for (const r of rows) {
  if (r.currency_code) {
    rates[r.currency_code] = Number(r.rate_to_base || 0);
  }
  byId[r.id] = {
    ...r,
    balance: Number(r.balance || 0),
    rate_to_base: Number(r.rate_to_base || 0),
    children: [],
    totals: {}
  };
}
for (const node of Object.values(byId)) {
  if (node.parent_id && byId[node.parent_id]) {
    byId[node.parent_id].children.push(node);
  } else {
    roots.push(node);
  }
}
function addToTotals(totals, currency, amount) {
  if (!currency) return;
  totals[currency] = (totals[currency] || 0) + Number(amount || 0);
}
function calculateTotals(node) {
  addToTotals(node.totals, node.currency_code, node.balance);
  for (const child of node.children) {
    const childTotals = calculateTotals(child);
    for (const [currency, amount] of Object.entries(childTotals)) {
      addToTotals(node.totals, currency, amount);
    }
  }
  return node.totals;
}
for (const root of roots) {
  calculateTotals(root);
}
function money(v) {
  return Number(v || 0).toLocaleString(locale, {
    minimumFractionDigits: 0,
    maximumFractionDigits: 0
  });
}
function money2(v) {
  return Number(v || 0).toFixed(2);
}
function formatTotals(totals) {
  return Object.entries(totals)
    .filter(([_, amount]) => Math.abs(Number(amount)) > 0.000001)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([currency, amount]) => `${money2(amount)} ${currency}`)
    .join(', ');
}
function totalInBase(totals) {
  let total = 0;
  for (const [currency, amount] of Object.entries(totals)) {
    const rate = currency === baseCurrency ? 1 : Number(rates[currency] || 0);
    if (!rate) continue;
    total += Number(amount || 0) * rate;
  }
  return total;
}
function render(node, level = 0) {
  const indent = level === 0 ? '' : '  '.repeat(level - 1) + '↳ ';
  const hasChildren = node.children.length > 0;
  const icon = hasChildren ? '📁' : '▫️';
  const totalsText = formatTotals(node.totals);
  const ownText = `${money2(node.balance)} ${node.currency_code}`;
  const baseTotal = totalInBase(node.totals);
  let line;
  if (hasChildren) {
    line = `${indent}${icon} ${node.name}`;
    if (totalsText) {
      line += ` — ${totalsText}`;
    }
    line += `\n${indent}≈ ${money(baseTotal)} ${baseCurrency}`;
  } else {
    line = `${indent}${icon} ${node.name} — ${ownText}`;
  }
  let text = line + '\n';
  node.children.sort((a, b) => {
    const ao = Number(a.sort_order || 999);
    const bo = Number(b.sort_order || 999);
    if (ao !== bo) return ao - bo;
    return String(a.name).localeCompare(String(b.name));
  });
  for (const child of node.children) {
    text += render(child, level + 1);
  }
  return text;
}
roots.sort((a, b) => {
  const ao = Number(a.sort_order || 999);
  const bo = Number(b.sort_order || 999);
  if (ao !== bo) return ao - bo;
  return String(a.name).localeCompare(String(b.name));
});
const grandTotals = {};
for (const root of roots) {
  for (const [currency, amount] of Object.entries(root.totals)) {
    addToTotals(grandTotals, currency, amount);
  }
}
let message = `${t.title}\n`;
message += `${t.baseCurrency}: ${baseCurrency}\n\n`;
for (const root of roots) {
  message += render(root) + '\n';
}
message += `${t.total}: ≈ ${money(totalInBase(grandTotals))} ${baseCurrency}\n\n`;
message += t.miniapp;
return [{
  json: {
    message: message.trim()
  }
}];

const rows = $('Command Summary').all().map(i => i.json);
const translations = $('Get Translations summary').all().map(i => i.json);
const tr = {};
for (const row of translations) {
  tr[`${row.module}.${row.message_key}`] = row.message_text;
}
const requiredKeys = [
  'summary.title',
  'summary.period',
  'summary.report_currency',
  'summary.empty',
  'summary.total',
  'summary.income',
  'summary.expense',
  'summary.adjustment',
  'summary.result',
  'summary.by_currency',
  'summary.rate',
  'summary.operations',
  'summary.today',
  'summary.yesterday',
  'common.miniapp'
];
const missing = requiredKeys.filter(key => !tr[key]);
if (missing.length > 0) {
  throw new Error(`Missing summary translations: ${missing.join(', ')}`);
}
const first = rows[0];
function periodLabel(row) {
  if (row.period_label === 'today') return tr['summary.today'];
  if (row.period_label === 'yesterday') return tr['summary.yesterday'];
  return row.period_label;
}
if (!first || !first.currency_code) {
  return [{
    json: {
      message: `${tr['summary.title']}\n\n${tr['summary.period']}: ${periodLabel(first || $('Parse Summary Period').first().json)}\n\n${tr['summary.empty']}\n\n${tr['common.miniapp']}`
    }
  }];
}
const reportCurrency = first.report_currency;
let totalIncome = 0;
let totalExpense = 0;
let totalAdjustment = 0;
let totalResult = 0;
let totalOperations = 0;
for (const r of rows) {
  if (!r.currency_code) continue;
  totalIncome += Number(r.income_report || 0);
  totalExpense += Number(r.expense_report || 0);
  totalAdjustment += Number(r.adjustment_report || 0);
  totalResult += Number(r.result_report || 0);
  totalOperations += Number(r.operations_count || 0);
}
function money(v) {
  return Number(v || 0).toFixed(2);
}
function rate(v) {
  return v === null || v === undefined ? '-' : Number(v).toFixed(4);
}
let text = `${tr['summary.title']}\n\n${tr['summary.period']}: ${periodLabel(first)}\n${tr['summary.report_currency']}: ${reportCurrency}\n\n`;
text += `${tr['summary.total']}:\n`;
text += `💰 ${tr['summary.income']}: ${money(totalIncome)} ${reportCurrency}\n`;
text += `💸 ${tr['summary.expense']}: ${money(totalExpense)} ${reportCurrency}\n`;
text += `⚖️ ${tr['summary.adjustment']}: ${money(totalAdjustment)} ${reportCurrency}\n`;
text += `${totalResult >= 0 ? '🟢' : '🔴'} ${tr['summary.result']}: ${money(totalResult)} ${reportCurrency}\n\n`;
text += `${tr['summary.by_currency']}:\n`;
for (const r of rows) {
  if (!r.currency_code) continue;
  const result = Number(r.result || 0);
  text += `\n${r.currency_code} (${tr['summary.rate']}: ${rate(r.rate_to_report)})\n`;
  text += `💰 ${money(r.income)}\n`;
  text += `💸 ${money(r.expense)}\n`;
  text += `⚖️ ${money(r.adjustment)}\n`;
  text += `${result >= 0 ? '🟢' : '🔴'} ${money(result)}\n`;
}
text += `\n${tr['summary.operations']}: ${totalOperations}`;
text += `\n\n${tr['common.miniapp']}`;
return [{ json: { message: text } }];

const text = ($('Get user context').first().json.message_text || '').trim().toLowerCase().replace(/\s+/g, ' ');
const lang =
  $('Get user context').first().json.language_code;

if (!lang) {
  throw new Error('Missing language_code in user context');
}
const now = new Date();
let dateFrom;
let dateTo;
let periodKey = 'month';
function formatDate(d) {
  return d.toISOString().slice(0, 10);
}
function monthLabel(d) {
  const localeMap = { ru: 'ru-RU', en: 'en-US', es: 'es-ES' };
  return d.toLocaleString(localeMap[lang] || 'en-US', { month: 'long', year: 'numeric' });
}
if (text === '/summary' || text === '/summary month') {
  dateFrom = new Date(now.getFullYear(), now.getMonth(), 1);
  dateTo = new Date(now.getFullYear(), now.getMonth() + 1, 0);
  periodKey = 'month';
} else if (text === '/summary today') {
  dateFrom = new Date(now);
  dateTo = new Date(now);
  periodKey = 'today';
} else if (text === '/summary yesterday') {
  dateFrom = new Date(now);
  dateFrom.setDate(dateFrom.getDate() - 1);
  dateTo = new Date(dateFrom);
  periodKey = 'yesterday';
} else if (text === '/summary year') {
  dateFrom = new Date(now.getFullYear(), 0, 1);
  dateTo = new Date(now.getFullYear(), 11, 31);
  periodKey = 'year';
} else {
  const ym = text.match(/^\/summary\s+(\d{4})-(\d{2})$/);
  const y = text.match(/^\/summary\s+(\d{4})$/);
  if (ym) {
    const year = Number(ym[1]);
    const month = Number(ym[2]);
    dateFrom = new Date(year, month - 1, 1);
    dateTo = new Date(year, month, 0);
    periodKey = 'custom_month';
  } else if (y) {
    const year = Number(y[1]);
    dateFrom = new Date(year, 0, 1);
    dateTo = new Date(year, 11, 31);
    periodKey = 'custom_year';
  } else {
    dateFrom = new Date(now.getFullYear(), now.getMonth(), 1);
    dateTo = new Date(now.getFullYear(), now.getMonth() + 1, 0);
    periodKey = 'month';
  }
}
let periodLabel;
if (periodKey === 'today') periodLabel = 'today';
else if (periodKey === 'yesterday') periodLabel = 'yesterday';
else if (periodKey === 'year' || periodKey === 'custom_year') periodLabel = String(dateFrom.getFullYear());
else periodLabel = monthLabel(dateFrom);
return [{
  json: {
    period_key: periodKey,
    period_label: periodLabel,
    date_from: formatDate(dateFrom),
    date_to: formatDate(dateTo)
  }
}];

const translations = $input.all().map(i => i.json);
