}
const params = $('Parse Last Parameters').first().json;
const limit = Number(params.limit || rows.length || 10);
const operationType = params.operation_type || 'all';
const scopeName = tr[operationType] || tr.all;
function money(v) {
  return Number(v || 0).toFixed(2);
}
function dateShort(value) {
  if (!value) return '--.--';
  const d = new Date(value);
