  periodKey = 'year';
} else {
  const ym = text.match(/^\/summary\s+(\d{4})-(\d{2})$/);
  const y = text.match(/^\/summary\s+(\d{4})$/);
  if (ym) {
    const year = Number(ym[1]);
    const month = Number(ym[2]);
    dateFrom = new Date(year, month - 1, 1);
    dateTo = new Date(year, month, 0);
    periodKey = 'custom_month';
  } else if (y) {
